public class BerekenVergoedingen {

    public static final Set<Sleutel<?>> BEREKEN_BRUTO_SLEUTEL = ImmutableSet.of(
            SleutelJaarWedde.INSTANCE, SleutelSalarisverhoging.INSTANCE, SleutelAfwijkendeIndex.INSTANCE, SleutelCategorie.INSTANCE,
            SleutelWerkgeversCategorie.INSTANCE, SleutelWerknemersKengetal.INSTANCE, SleutelPensioenStelsel.INSTANCE, SleutelRekenWijze.INSTANCE,
            SleutelUurNoemer.INSTANCE, SleutelJaarNaarMaand.INSTANCE, SleutelRszDagenStelsel.INSTANCE, SleutelPrestatieVerhoudingVorming.INSTANCE,
            SleutelTellerPrestatieVerhouding.INSTANCE, SleutelNoemerPrestatieVerhouding.INSTANCE, SleutelAfwezigheidsCode.INSTANCE,
            SleutelStatuutDmfappl.INSTANCE, SleutelVergoedingen.INSTANCE, SleutelAanstelling.INSTANCE, SleutelMaatman.INSTANCE,
            SleutelAfwezigheidsUren.INSTANCE, SleutelMaatregelingReorganisatieArbeidsTijd.INSTANCE,
            SleutelMaatregelingReorganisatieArbeidsTijd2.INSTANCE, SleutelAfwezighedenInvoerModule.INSTANCE, SleutelAfwijkendeIndexFederaal.INSTANCE);

    private static final int SCALE = 2;

    private final NlpGlobalService globalService;
    private final ConstantManager constantManager;

    private final BepaalJaarNaarMaand bepaalJaarNaarMaand = new BepaalJaarNaarMaand();
    private final DiplomaToeslag diplomaToeslag;
    private final VerwerkPrestaties verwerkPrestaties;


    public BerekenVergoedingen(ConstantManager constantManager, NlpGlobalService service, LoonElementVerwerker loonElementVerwerker) {
        this.globalService = service;
        this.constantManager = constantManager;
        this.diplomaToeslag = DiplomaToeslag.builder()
                .constantManager(constantManager)
                .globalService(globalService)
                .loonElementVerwerker(loonElementVerwerker)
                .build();
        this.verwerkPrestaties = new VerwerkPrestaties(constantManager, loonElementVerwerker);
    }

    public void bereken(RekenContext context, Opdracht opdracht) {
        SleutelSamenNemer aggregator = new SleutelSamenNemer();
        List<SleutelGegevens> aggregaten = aggregator.neemSamenVoorSleutel(opdracht, BEREKEN_BRUTO_SLEUTEL);
        MoneyMap<AardKodeExtensie> carryoverMap = new HashMoneyMap<>();
        for (SleutelGegevens aggregaat : aggregaten) {
            if (aggregaat.getRekenWijze() != Rekenwijze.PRESTATIE) {
                List<LoonElement> loonElementen = vormVergoedingenElementen(context, aggregaat);
                herverdeelSleutelGegevens(context, aggregaat, loonElementen);
                verwerkPrestaties.verwerk(context, aggregaat, carryoverMap);
            }
        }
        diplomaToeslag.bereken(context, opdracht, carryoverMap);
    }

    private void herverdeelSleutelGegevens(RekenContext context, SleutelGegevens aggregaat, List<LoonElement> aggregaatElementen) {
        LoonElementManager manager = context.getLoonElementManager();
        RekenTijd rekenTijd = context.getRekenTijd();
        Set<Opper> oppers = aggregaat.getOppers();
        for (LoonElement element : aggregaatElementen) {
            Money jaarBedrag = element.getPropertyMoney(JAARBEDRAG_KEY);
            Money basisBedrag = element.getPropertyMoney(BASIS_BEDRAG_KEY);
            Money basisGeboorteBedrag = element.getPropertyMoney(BASIS_GEBOORTEBEDRAG_KEY);
            Money basisQuarantaineBedrag = element.getPropertyMoney(BASIS_QUARANTAINEBEDRAG_KEY);

            AardKodeExtensie loonCode = element.getAardKodeExtensie();
            boolean isCompensatoire = loonCode.behoortTotGroep(LooncodeGroepKeyStrings.KEDSPECIAALTYPE_COMPENSATOIRE_KEY);
            for (Opper opper : oppers) {
                LocalDateInterval periode = opper.getActualInterval().overlap(rekenTijd.rekenPeriode);
                if (loonCode.isForfaitair() || isCompensatoire) {
                    basisBedrag = berekenAlsForfaitairOfCompensatoire(jaarBedrag, periode);
                }
                LoonElement opperElement = new LoonElement(element.getAardKodeExtensie());
                opperElement.putProperty(JAARBEDRAG_KEY, jaarBedrag);
                opperElement.putProperty(BASIS_BEDRAG_KEY, basisBedrag);
                if (basisGeboorteBedrag.signum() != 0) {
                    opperElement.putProperty(BASIS_GEBOORTEBEDRAG_KEY, basisGeboorteBedrag);
                }
                if (basisQuarantaineBedrag.signum() != 0) {
                    opperElement.putProperty(BASIS_QUARANTAINEBEDRAG_KEY, basisQuarantaineBedrag);
                }
                manager.addLoonElement(opperElement, opper);
            }
        }
    }

    private Money berekenAlsForfaitairOfCompensatoire(Money bedrag, LocalDateInterval periode) {
        bedrag = bedrag.divide(RekenTools.TWELVE).round(SCALE);
        int aantalDagen = periode.getAantalDagen();
        int kalenderdagen = periode.getStart().dayOfMonth().getMaximumValue();
        return bedrag.multiply(aantalDagen).divide(kalenderdagen).round(SCALE);
    }

    /*
     * http://superwiki/lpb/32571-sw.html
     */
    public List<LoonElement> vormVergoedingenElementen(RekenContext context, SleutelGegevens aggregaat) {
        RekenTijd rekenTijd = context.getRekenTijd();
        LoonCodeManager loonCodeManager = context.getLoonCodeManager();

        AardKodeExtensie looncodeGewoonLoon = bepaalLooncodeGewoonLoon(context, aggregaat);
        LoonElement normaalLoon = new LoonElement(looncodeGewoonLoon);

        Money jaarLoon = aggregaat.getJaarWedde().add(aggregaat.getSalarisverhoging());
        Indexator indexator = context.getUnchecked(INDEXATOR_KEY);
        jaarLoon = indexator.indexeer(jaarLoon, looncodeGewoonLoon, aggregaat);
        normaalLoon.putProperty(JAARBEDRAG_KEY, jaarLoon);
        List<LoonElement> loonElementen = new ArrayList<>();
        loonElementen.add(normaalLoon);
        boolean geval170 = LoonCodeTools.isGeval170(looncodeGewoonLoon);

        RegulManager regulManager = context.getRegulManager();
        RkmCoreHrConfiguratieManager rkmCoreHrConfiguratieManager = context.getUnchecked(RKM_COREHR_CONFIG_MANAGER);
        RkmCoreHrConfiguratie rkmCoreHrConfiguratie = rkmCoreHrConfiguratieManager.getRkmCoreHrConfiguratie(aggregaat.getOpdracht(), rekenTijd);
        LoonCodeCalculatorFactory factory = new LoonCodeCalculatorFactory(constantManager, regulManager, loonCodeManager, globalService, rkmCoreHrConfiguratie);
        MoneyMap<AardKodeExtensie> vergoedingToBedragMap = maakVergoedingToBedragMap(loonCodeManager, aggregaat.getVergoedingen());
        for (AardKodeExtensie aardKodeExtensie : vergoedingToBedragMap.keySet()) {
            LoonElement element = new LoonElement(aardKodeExtensie);
            LoonCodeCalculator calculator = factory.genereerLoonCodeCalculator(aggregaat, aardKodeExtensie, rekenTijd);
            Money bedrag = calculator.berekenBedrag100Percent(vergoedingToBedragMap.getMoney(aardKodeExtensie));
            bedrag = indexator.indexeer(bedrag, aardKodeExtensie, aggregaat);
            if (bedrag.signum() != 0 && !geval170) {
                element.putProperty(JAARBEDRAG_KEY, bedrag);
                loonElementen.add(element);
            } else if (bedrag.signum() != 0) {
                normaalLoon.addToProperty(JAARBEDRAG_KEY, bedrag);
            } else if (BerekenTerugbetalingSocialeBijdragen.isLoonElementTerugbetalingRsz(element)) {
                loonElementen.add(element);
            } else {
                //do nothing
            }
        }

        bepaalBasisBedrag(context, aggregaat, loonElementen);

        voegGrensBedragenToe(context, aggregaat, rekenTijd, regulManager, normaalLoon);

        return loonElementen;
    }

    private AardKodeExtensie bepaalLooncodeGewoonLoon(RekenContext context, SleutelGegevens aggregaat) {
        RekenTijd rekenTijd = context.getRekenTijd();
        LoonCodeManager loonCodeManager = context.getLoonCodeManager();

        GewoonLoon gewoonloon = GewoonLoonFactory.getGewoonLoon(loonCodeManager, rekenTijd);
        AardKodeExtensie looncodeGewoonLoon = gewoonloon.bepaalAardKodeExtensie(aggregaat);
        context.put(LOONCODE_GEWOON_LOON_KEY, looncodeGewoonLoon);
        return looncodeGewoonLoon;
    }

    private MoneyMap<AardKodeExtensie> maakVergoedingToBedragMap(LoonCodeManager loonCodeManager, Set<Vergoeding> vergoedingen) {
        MoneyMap<AardKodeExtensie> vergoedingToBedragMap = new HashMoneyMap<>();
        for (Vergoeding vergoeding : vergoedingen) {
            AardKodeExtensie aardKodeExtensie = loonCodeManager.getByVergoeding(vergoeding);
            vergoedingToBedragMap.addToMoney(aardKodeExtensie, vergoeding.getBedragWerknemer());
        }
        return vergoedingToBedragMap;
    }

    private void bepaalBasisBedrag(RekenContext context, SleutelGegevens aggregaat, List<LoonElement> loonElementen) {
        RekenTijd rekenTijd = context.getRekenTijd();
        RegulManager regulManager = context.getRegulManager();
        for (LoonElement element : loonElementen) {
            Money bedrag = element.getPropertyMoney(JAARBEDRAG_KEY);
            AardKodeExtensie loonCode = element.getAardKodeExtensie();

            boolean isCompensatoire = loonCode.behoortTotGroep(LooncodeGroepKeyStrings.KEDSPECIAALTYPE_COMPENSATOIRE_KEY);
            if (!loonCode.isForfaitair() && !isCompensatoire) {
                UitzPerUurModus uitzPerUurModus = context.getUnchecked(UITZONDERLIJK_PER_UUR_KEY);
                boolean begroting = context.getBoolean(BEGROTING_KEY);
                bedrag = jaarNaarBasis(bedrag, aggregaat, rekenTijd, uitzPerUurModus, regulManager, begroting);
            }
            element.putProperty(BASIS_BEDRAG_KEY, bedrag);
        }
    }

    public Money jaarNaarBasis(
            Money bedrag, SleutelGegevens aggregaat, RekenTijd rekenTijd, UitzPerUurModus uitzPerUurModus, RegulManager regulManager, boolean begroting) {
        if (aggregaat.getRekenWijze() == Rekenwijze.MAAND) {
            BigDecimal jaarNaarBasis = jaarNaarMaand(aggregaat, rekenTijd, regulManager);
            BigDecimal prestatieVerhouding = RkmPrestatieVerhouding.bepaal(aggregaat, uitzPerUurModus, regulManager, begroting);
            bedrag = bedrag.divide(jaarNaarBasis).multiply(prestatieVerhouding).round(SCALE);
        } else {
            if (aggregaat.getRekenWijze() == Rekenwijze.UUR && bedrag.signum() != 0) {
                BigDecimal jaarNaarBasis = BigDecimal.valueOf(aggregaat.getUurNoemer());
                bedrag = bedrag.divide(jaarNaarBasis);
            }
        }
        return bedrag;
    }

    private BigDecimal jaarNaarMaand(SleutelGegevens aggregaat, RekenTijd rekenTijd, RegulManager regulManager) {
        Jaar2maand jaarNaarMaandType = aggregaat.getJaarNaarMaand();
        if (jaarNaarMaandType == null || jaarNaarMaandType == Jaar2maand.NVT) {
            regulManager.doRegulException(aggregaat.getOpdracht(), Regulkode.ONGELDIGE_JAARNAARMAAND);
            jaarNaarMaandType = Jaar2maand.TWAALF_MAANDEN;
        }
        return bepaalJaarNaarMaand.bepaal(jaarNaarMaandType, aggregaat.getRszDagenStelsel(), rekenTijd.beginDatum);
    }

    private void voegGrensBedragenToe(RekenContext context, SleutelGegevens aggregaat, RekenTijd rekenTijd, RegulManager regulManager, LoonElement normaalLoon) {
        grensBedragPerType(context, aggregaat, rekenTijd, regulManager, normaalLoon, Konstanten.GRNS_BDRG_GEBOORTEVERLOF, BASIS_GEBOORTEBEDRAG_KEY);
        grensBedragPerType(context, aggregaat, rekenTijd, regulManager, normaalLoon, Konstanten.GRNS_BDRG_QUARANTAINEVERLOF, BASIS_QUARANTAINEBEDRAG_KEY);
    }

    private void grensBedragPerType(
            RekenContext context, SleutelGegevens aggregaat, RekenTijd rekenTijd, RegulManager regulManager, LoonElement normaalLoon, Konstanten grnsBedragConstante,
            RekenBrutoKey grnsBedragKey) {
        Money jaarLoon = normaalLoon.getPropertyMoney(JAARBEDRAG_KEY);
        Money grensBedrag = constantManager.getActualConstant(grnsBedragConstante, rekenTijd).getMoney();
        Indexator indexator = context.getUnchecked(INDEXATOR_KEY);
        grensBedrag = indexator.indexeerGrensBedragen(grensBedrag, aggregaat);

        if (jaarLoon.getAmount().compareTo(grensBedrag.getAmount()) >= 0) {
            UitzPerUurModus uitzPerUurModus = context.getUnchecked(UITZONDERLIJK_PER_UUR_KEY);
            boolean begroting = context.getBoolean(BEGROTING_KEY);
            grensBedrag = jaarNaarBasis(grensBedrag, aggregaat, rekenTijd, uitzPerUurModus, regulManager, begroting);
            normaalLoon.putProperty(grnsBedragKey, grensBedrag);
        }
    }

}
